int main() {
    int n;
    cin >> n;
    vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        cin >> a[i];
    }

    if (n == 1) {
        cout << 0 << endl;
        return 0;
    }

    set<int> unique_vals(a.begin(), a.end());
    vector<int> candidates;
    for (int val : unique_vals) {
        candidates.push_back(val);
    }

    // Also consider midpoints between distinct values
    for (int i = 0; i < (int)candidates.size(); ++i) {
        for (int j = i + 1; j < (int)candidates.size(); ++j) {
            int x = candidates[i];
            int y = candidates[j];
            if ((x + y) % 2 == 0) {
                int mid = (x + y) / 2;
                candidates.push_back(mid);
            }
        }
    }

    int best = INT_MAX;
    for (int target : candidates) {
        int D = -1;
        bool ok = true;
        for (int i = 0; i < n; ++i) {
            int diff = abs(a[i] - target);
            if (diff == 0) continue;
            if (D == -1) {
                D = diff;
            } else if (diff != D) {
                ok = false;
                break;
            }
        }
        if (ok) {
            if (D == -1) D = 0; // all elements already equal target
            best = min(best, D);
        }
    }

    if (best == INT_MAX) {
        cout << -1 << endl;
    } else {
        cout << best << endl;
    }

    return 0;
}

