bool canMakeEqual(const vector<int>& a) {
    int n = a.size();
    // Check if all equal initially
    bool allEqual = true;
    for (int i = 1; i < n; ++i) {
        if (a[i] != a[0]) {
            allEqual = false;
            break;
        }
    }
    if (allEqual) return true;

    // Check if 1 is present
    bool hasOne = false;
    for (int x : a) {
        if (x == 1) {
            hasOne = true;
            break;
        }
    }
    if (hasOne) {
        // All must be 1
        for (int x : a) {
            if (x != 1) return false;
        }
        return true;
    }

    // No 1 present: check consecutive difference of 1 after sorting
    vector<int> b = a;
    sort(b.begin(), b.end());
    for (int i = 1; i < n; ++i) {
        if (b[i] - b[i-1] == 1) return false;
    }
    return true;
}

