    for (int i = 0; i < n; ++i) {
        cin >> grid[i];
    }

    long long total = 0;

    // Brute force all possible diamond centers and sizes
    // A diamond of side length s (number of cells along one diagonal direction)
    // has 2*s - 1 rows and columns in its bounding box.
    // Center (i,j) is the middle cell.
    // For each possible center (i,j) and side length s (>=1)
    // check if all cells in the diamond have the same color.

    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < m; ++j) {
            // maximum possible side length from this center
            int max_s = min({i+1, j+1, n-i, m-j});
            for (int s = 1; s <= max_s; ++s) {
                // check diamond of side length s centered at (i,j)
                bool valid = true;
                char col = grid[i][j];
                // iterate over all cells in the diamond
                for (int di = -(s-1); di <= (s-1); ++di) {
                    int row = i + di;
                    int col_offset = s - 1 - abs(di);
                    for (int dj = -col_offset; dj <= col_offset; dj += 2) {
                        int colj = j + dj;
                        if (row < 0 || row >= n || colj < 0 || colj >= m) {
                            valid = false;
                            break;
                        }
                        if (grid[row][colj] != col) {
                            valid = false;
                            break;
                        }
                    }
                    if (!valid) break;
                }
                if (valid) {
                    total++;
                } else {
                    // if a diamond of size s is invalid, larger ones will also be invalid
                    break;
                }
            }
        }
    }

    cout << total << "\n";
