    // There are k^n possible sequences of choices.
    // We'll iterate over all sequences using recursion or iterative enumeration.
    // Since n and k are small (<=12), k^n is at most 12^12 ~ 8.9e12, which is too large.
    // But we can use linearity of expectation: for each a[i], expected contribution is
    // (1/k) * sum_{j=0}^{k-1} (a[i] - a[i] % (j+1))
    // So we can compute per element and sum.

    long long total_expected = 0;
    for (int i = 0; i < n; i++) {
        long long sum_contrib = 0;
        for (int j = 0; j < k; j++) {
            int d = j + 1;
            sum_contrib += (a[i] - (a[i] % d));
        }
        // expected contribution for this element = sum_contrib / k
        // We'll keep everything as fractions modulo MOD later.
        total_expected += sum_contrib;
    }
    // Now total_expected is the sum over i of sum_contrib_i.
    // The true expected value E = total_expected / (n * k) ??? Wait careful:
    // For each element, expected contribution = (1/k) * sum_{j} (a[i] - a[i]%(j+1))
    // So total expected ans = sum_i [ (1/k) * sum_{j} (a[i] - a[i]%(j+1)) ]
    // = (1/k) * total_expected   (since total_expected defined as sum_i sum_j ...)
    // Thus E = total_expected / k.
    // But we need E * n^k mod MOD.
    // So answer = (total_expected / k) * n^k mod MOD.
    // Since division by k modulo MOD means multiply by inverse of k.

    long long inv_k = modpow(k, MOD - 2);
    long long n_pow_k = modpow(n, k);
    long long ans = (total_expected % MOD) * inv_k % MOD * n_pow_k % MOD;
