    int N;
    cin >> N;
    vector<int> A(N);
    for (int i = 0; i < N; i++) {
        cin >> A[i];
    }

    vector<vector<int>> adj(N);
    for (int i = 0; i < N - 1; i++) {
        int u, v;
        cin >> u >> v;
        u--; v--;
        adj[u].push_back(v);
        adj[v].push_back(u);
    }

    // Precompute distances using BFS from every node (since N ≤ 12, O(N^2) is fine)
    vector<vector<int>> dist(N, vector<int>(N, -1));
    for (int s = 0; s < N; s++) {
        queue<int> q;
        dist[s][s] = 0;
        q.push(s);
        while (!q.empty()) {
            int u = q.front(); q.pop();
            for (int v : adj[u]) {
                if (dist[s][v] == -1) {
                    dist[s][v] = dist[s][u] + 1;
                    q.push(v);
                }
            }
        }
    }

    // Function to compute f(x,y,z)
    auto f = [&](int x, int y, int z) -> int {
        // Minimum edges to connect three nodes = (dist(x,y) + dist(y,z) + dist(z,x)) / 2
        int dxy = dist[x][y];
        int dyz = dist[y][z];
        int dzx = dist[z][x];
        return (dxy + dyz + dzx) / 2;
    };

    // Function to compute g(x,y,z) = number of distinct prime factors of gcd(A[x],A[y],A[z])
    auto g = [&](int x, int y, int z) -> int {
        int g = __gcd(A[x], __gcd(A[y], A[z]));
        if (g <= 1) return 0;
        int cnt = 0;
        int temp = g;
        for (int p = 2; p * p <= temp; p++) {
            if (temp % p == 0) {
                cnt++;
                while (temp % p == 0) temp /= p;
            }
        }
        if (temp > 1) cnt++;
        return cnt;
    };

    long long ans = 0;
    for (int x = 0; x < N; x++) {
        for (int y = x + 1; y < N; y++) {
            for (int z = y + 1; z < N; z++) {
                long long val = 1LL * f(x, y, z) * g(x, y, z);
                ans = (ans + val) % MOD;
            }
        }
    }

    cout << ans << "\n";
    return 0;
}
